import { motion } from "motion/react";
import type { ReactNode, ButtonHTMLAttributes } from "react";
import styles from "./Button.module.scss";

interface ButtonProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "className"> {
  variant?: "primary" | "secondary" | "ghost";
  size?: "sm" | "md" | "lg";
  children: ReactNode;
  className?: string;
  href?: string;
}

export function Button({
  variant = "primary",
  size = "md",
  children,
  className,
  href,
  ...props
}: ButtonProps) {
  const classNames = [
    styles.button,
    styles[variant],
    styles[size],
    className,
  ]
    .filter(Boolean)
    .join(" ");

  if (href) {
    return (
      <motion.a
        href={href}
        className={classNames}
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.98 }}
      >
        {children}
      </motion.a>
    );
  }

  return (
    <motion.button
      className={classNames}
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      {...props}
    >
      {children}
    </motion.button>
  );
}

@use "../../styles/variables" as *;
@use "../../styles/mixins" as *;

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: $space2;
  font-weight: 600;
  border-radius: $radiusMd;
  transition: all $transitionBase;
  cursor: pointer;
  border: none;
  text-align: center;
  white-space: nowrap;

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    pointer-events: none;
  }

  &:focus-visible {
    @include focusRing;
  }
}

.sm {
  height: 32px;
  padding: 0 $space4;
  font-size: $fontSize13;
}

.md {
  height: 40px;
  padding: 0 $space6;
  font-size: $fontSize14;
}

.lg {
  height: 48px;
  padding: 0 $space8;
  font-size: $fontSize16;
}

.primary {
  background: linear-gradient(135deg, $accentPurple 0%, $accentPurpleLight 100%);
  color: $textPrimary;
  box-shadow: $shadowSm;

  &:hover {
    box-shadow: $shadowGlow;
  }
}

.secondary {
  @include glass;
  color: $accentPurple;
  border-color: $accentPurple;

  &:hover {
    @include glassHover;
    border-color: $accentPurpleLight;
  }
}

.ghost {
  background: transparent;
  color: $textPrimary;

  &:hover {
    background: rgba(255, 255, 255, 0.05);
  }
}

import type { ReactNode, InputHTMLAttributes } from "react";
import styles from "./Input.module.scss";

interface InputProps extends Omit<InputHTMLAttributes<HTMLInputElement>, "className"> {
  label?: string;
  error?: string;
  icon?: ReactNode;
  className?: string;
}

export function Input({
  label,
  error,
  icon,
  className,
  ...props
}: InputProps) {
  return (
    <div className={[styles.wrapper, className].filter(Boolean).join(" ")}>
      {label && <label className={styles.label}>{label}</label>}
      <div className={styles.inputWrapper}>
        {icon && <div className={styles.icon}>{icon}</div>}
        <input
          className={`${styles.input} ${icon ? styles.hasIcon : ""} ${error ? styles.error : ""}`}
          {...props}
        />
      </div>
      {error && <span className={styles.errorMessage}>{error}</span>}
    </div>
  );
}

